import{_ as o,C as t,o as r,c as s,a2 as e,E as n}from"./chunks/framework.BKG_UbFK.js";const b=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"it/features/dashboard.md","filePath":"it/features/dashboard.md"}'),l={name:"it/features/dashboard.md"};function d(c,a,u,h,p,m){const i=t("Screenshot");return r(),s("div",null,[a[0]||(a[0]=e('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>La Dashboard è la pagina di atterraggio del pannello Clearance. Offre un riepilogo a colpo d&#39;occhio dello stato di autorizzazione della tua applicazione - nessuna configurazione richiesta.</p><h2 id="cosa-mostra" tabindex="-1">Cosa mostra <a class="header-anchor" href="#cosa-mostra" aria-label="Permalink to &quot;Cosa mostra&quot;">​</a></h2><ul><li><strong>Ruoli totali</strong> - conteggio di tutti i ruoli Spatie.</li><li><strong>Guardie totali</strong> - conteggio di tutte le guardie gestite da Clearance (vedi <a href="/clearance-docs/it/features/guards.html">Guardie</a>).</li><li><strong>Permessi totali</strong> - conteggio di tutti i permessi Spatie.</li><li><strong>Gruppi di permessi</strong> - il numero di gruppi di permessi distinti, derivato dal prefisso di naming (il <code>group</code> in <code>group-action</code>, es. <code>orders</code> in <code>orders-create</code>). Vedi <a href="/clearance-docs/it/features/permissions.html">Permessi</a> per la convenzione di naming.</li><li><strong>Assegnazioni di ruolo contestuali</strong> - il numero di assegnazioni di ruolo limitate a una specifica istanza di modello (uno Store, un Tenant, un Project). Vedi <a href="/clearance-docs/it/features/contextual-authorization.html">Contextual Authorization</a>.</li><li><strong>Top 5 ruoli per numero di utenti</strong> - i cinque ruoli con più utenti assegnati, classificati.</li></ul>',4)),n(i,{src:"/screenshots/dashboard-page.png",alt:"Dashboard di Clearance che mostra i conteggi di ruoli, guardie e permessi",caption:"La Dashboard riassume ruoli, guardie, permessi, gruppi, assegnazioni contestuali, e i ruoli principali."}),a[1]||(a[1]=e('<h2 id="accedere-alla-dashboard" tabindex="-1">Accedere alla Dashboard <a class="header-anchor" href="#accedere-alla-dashboard" aria-label="Permalink to &quot;Accedere alla Dashboard&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nome route</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>Dashboard</td></tr></tbody></table><p>Leggere la Dashboard richiede il permesso <code>clearance-access</code>, come ogni altra sezione del pannello. Vedi <a href="/clearance-docs/it/features/super-admin.html#panel-access-fine-grained-write-permissions">Super Admin</a> per la tabella completa di controllo accessi.</p><h2 id="incorporare-il-componente" tabindex="-1">Incorporare il componente <a class="header-anchor" href="#incorporare-il-componente" aria-label="Permalink to &quot;Incorporare il componente&quot;">​</a></h2><p>La Dashboard è un componente Livewire autonomo. Montala ovunque nei tuoi layout, in aggiunta - o in alternativa - alla route predefinita <code>/clearance</code>:</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="prossimi-passi" tabindex="-1">Prossimi passi <a class="header-anchor" href="#prossimi-passi" aria-label="Permalink to &quot;Prossimi passi&quot;">​</a></h2><ul><li><a href="/clearance-docs/it/features/permissions.html">Permessi</a> - gestisci l&#39;elenco di permessi che alimenta i conteggi della Dashboard.</li><li><a href="/clearance-docs/it/features/roles.html">Ruoli</a> - gestisci i ruoli dietro la statistica &quot;top 5 per numero di utenti&quot;.</li><li><a href="/clearance-docs/it/features/contextual-authorization.html">Contextual Authorization</a> - cos&#39;è un&#39;assegnazione di ruolo contestuale.</li></ul>',8))])}const f=o(l,[["render",d]]);export{b as __pageData,f as default};
